function solve(nums, k) {
    const n = nums.length;

    // Precompute prefix maximums: prefixMax[i] = max(nums[0..i])
    const prefixMax = new Array(n);
    let currentMax = -Infinity;
    for (let i = 0; i < n; i++) {
        currentMax = Math.max(currentMax, nums[i]);
        prefixMax[i] = currentMax;
    }

    // Precompute suffix minimums: suffixMin[i] = min(nums[i..n-1])
    const suffixMin = new Array(n);
    let currentMin = Infinity;
    for (let i = n - 1; i >= 0; i--) {
        currentMin = Math.min(currentMin, nums[i]);
        suffixMin[i] = currentMin;
    }

    // Check each index i
    for (let i = 0; i < n; i++) {
        // Unstable value for index i: max(nums[0..i]) - min(nums[i..n-1])
        const unstableValue = prefixMax[i] - suffixMin[i];

        // Check if it is a stable index
        if (unstableValue <= k) {
            // Return the smallest stable index found
            return i;
        }
    }

    // If no stable index is found
    return -1;
}
